object Solution { def flatten_config(config: Map[String, Any]): Map[String, Any] = { val out = scala.collection.mutable.Map[String, Any](); def walk(node: Map[String, Any], prefix: String): Unit = for ((key, value) <- node) { val path = if (prefix.isEmpty) key else prefix + "." + key; value match { case child: Map[_, _] => walk(child.asInstanceOf[Map[String, Any]], path); case leaf => out(path) = leaf } }; walk(config, ""); out.toMap } }
